import React, { useRef, useEffect } from 'react';
import { AppBar, Toolbar, Typography, IconButton, Drawer, Box } from '@mui/material';
import { Brush as BrushIcon } from '@mui/icons-material';

function App() {
  const canvasRef = useRef(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    ctx.fillStyle = '#fff';
    ctx.fillRect(0, 0, canvas.width, canvas.height);
    // Draw grid
    ctx.save();
    ctx.strokeStyle = '#e0e0e0';
    ctx.lineWidth = 0.5;
    const gridSpacing = 20;
    for (let x = 0; x <= canvas.width; x += gridSpacing) {
      ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, canvas.height); ctx.stroke();
    }
    for (let y = 0; y <= canvas.height; y += gridSpacing) {
      ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(canvas.width, y); ctx.stroke();
    }
    // Axes
    ctx.strokeStyle = '#888';
    ctx.lineWidth = 1.5;
    ctx.beginPath(); ctx.moveTo(canvas.width/2, 0); ctx.lineTo(canvas.width/2, canvas.height); ctx.stroke();
    ctx.beginPath(); ctx.moveTo(0, canvas.height/2); ctx.lineTo(canvas.width, canvas.height/2); ctx.stroke();
    ctx.restore();
  }, []);

  return (
    <Box sx={{ height: '100vh', display: 'flex', flexDirection: 'column' }}>
      <AppBar position="static">
        <Toolbar>
          <Typography variant="h6" sx={{ flexGrow: 1 }}>Draze - Where Shapes Take Form</Typography>
          <IconButton color="inherit"><BrushIcon /></IconButton>
        </Toolbar>
      </AppBar>
      <Box sx={{ display: 'flex', flexGrow: 1 }}>
        <Drawer variant="permanent" open anchor="left" sx={{ width: 240, flexShrink: 0 }}
          PaperProps={{ sx: { width: 240, boxSizing: 'border-box', padding: 2 } }}>
          <Typography variant="subtitle1" sx={{ mt: 2, mb: 1 }}>TOOLS</Typography>
        </Drawer>
        <Box sx={{ flexGrow: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', bgcolor: '#f9fafb' }}>
          <canvas ref={canvasRef} width={600} height={450} style={{ border: '1px solid #e5e7eb', background: '#fff', borderRadius: 6 }} />
        </Box>
      </Box>
    </Box>
  );
}

export default App;
